INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1143, 188308, 13, 3, 'Beaujolais Nouveau', '我在新浪上看到一篇关于Beaujolais Nouveau的帖子，觉得挺感人，后来在网上查了相关的资料，阅读下来就有了写点文字的欲望。就好比那篇文章中的作者说的，喝红酒么，是要找些理由的，象我这般岁数的人，写点东西，也是要有些理由的呵呵。
<br>
<br>Beaujolais Nouveau是一种红酒，产于翻过勃艮第地区南边的Beaujolais区，法语发音(boh-zhu-lay)，有人把它译成&quot;薄酒来&quot;，发音相近，而且词义贴切，因为该地区的葡萄酒一向以清淡著称，Nouveau是&quot;新的&quot;或是&quot;新制成的&quot;的意思，发音为(nuvo)，Beaujolais Nouveau就是指薄酒来区用当年采收的葡萄新酿的酒。
<br>
<br>因为一般葡萄酒是需要经过一段时间的酝酿和陈年储藏后才能上市销售，而且古话说酒越沉越香，所以Beaujolais Nouveau就显得很特别。Beaujolais Nouveau是每年十一月的第三个星期四上市，秋季收获葡萄用来酿制的酒，不到两个月的日子就拿出来开盖品尝，想想，都能感觉到一种果香的味道和一种新鲜的气质。Beaujolais Nouveau是用一种叫「嘉美」(Gamay)的葡萄酿的，其特点就是果味重，说是葡萄酒，更象果酒，尤其富香蕉、莓果、及桃子三种果香。
<br>
<br>这么新鲜的东西，自然是适合立即饮用的，通常上市后三个月后就不能再喝了，若错过，只能等待来年的新酒了。Beaujolais Nouveau适饮的温度是10到14度，所以需要加冰才能充分展现Beaujolais Nouveau的水果芬香。
<br>
<br>那篇帖子没有提到上面这些我搜集整理的背景资料。文章讲的是爷爷在世的时候，家里每年十一月的第三个星期四就要过new wine party，一家人聚在一起，喝新酒，聊天，然后吃奶奶做的西点，很温情。老人家过世后就没有再延续这个传统了，直至作者去马赛公干的时候发现法国人也过这个节日，作者买了两瓶独自在酒店里边喝边回忆童年。之后作者不管有多忙都会在那天买一瓶Beaujolais Nouveau回家和父母一起喝酒聊天。一瓶叫Beaujolais Nouveau的红酒，一个节日，能串起亲情来，看着就觉得有些感动。
<br>
<br>作者后来回了一篇帖子，则是浪漫之极。回帖里讲了两件事。一件是他结婚的时候，送给他岳母的礼物是他太太出生那年的一瓶勃艮底酒，是在一家专买纪念酒的网站上买的，很贵。他岳母很感动，因为那瓶红酒让她回忆起很多往事。另外一件是后来他有了一个女儿，他收藏了一箱2000年出品的红酒，他会在她出嫁那天和所有的客人一起喝。
<br>
<br>呵，浪漫得让人有种立刻生个女儿的冲动，然后收集一箱，Beaujolais Nouveau虽然好但是无法保存二十来个年头，还是一箱张裕或者长城干红好了，然后等到她出嫁的时候请所有的客人一起喝。', '我在新浪上看到一篇关于Beaujolais Nouveau的帖子，觉得挺感人，后来在网上查了相关的资料，阅读下来就有了写点文字的欲望。就好比那篇文章中的作者说的，喝红酒么，是要找些理由的，象我这般岁数的人，写点东西，也是要有些理由的呵呵。

Beaujolais Nouveau是一种红酒，产于翻过勃艮第地区南边的Beaujolais区，法语发音(boh-zhu-lay)，有人把它译成"薄酒来"，发音相近，而且词义贴切，因为该地区的葡萄酒一向以清淡著称，Nouveau是"新的"或是"新制成的"的意思，发音为(nuvo)，Beaujolais Nouveau就是指薄酒来区用当年采收的葡萄新酿的酒。

因为一般葡萄酒是需要经过一段时间的酝酿和陈年储藏后才能上市销售，而且古话说酒越沉越香，所以Beaujolais Nouveau就显得很特别。Beaujolais Nouveau是每年十一月的第三个星期四上市，秋季收获葡萄用来酿制的酒，不到两个月的日子就拿出来开盖品尝，想想，都能感觉到一种果香的味道和一种新鲜的气质。Beaujolais Nouveau是用一种叫「嘉美」(Gamay)的葡萄酿的，其特点就是果味重，说是葡萄酒，更象果酒，尤其富香蕉、莓果、及桃子三种果香。

这么新鲜的东西，自然是适合立即饮用的，通常上市后三个月后就不能再喝了，若错过，只能等待来年的新酒了。Beaujolais Nouveau适饮的温度是10到14度，所以需要加冰才能充分展现Beaujolais Nouveau的水果芬香。

那篇帖子没有提到上面这些我搜集整理的背景资料。文章讲的是爷爷在世的时候，家里每年十一月的第三个星期四就要过new wine party，一家人聚在一起，喝新酒，聊天，然后吃奶奶做的西点，很温情。老人家过世后就没有再延续这个传统了，直至作者去马赛公干的时候发现法国人也过这个节日，作者买了两瓶独自在酒店里边喝边回忆童年。之后作者不管有多忙都会在那天买一瓶Beaujolais Nouveau回家和父母一起喝酒聊天。一瓶叫Beaujolais Nouveau的红酒，一个节日，能串起亲情来，看着就觉得有些感动。

作者后来回了一篇帖子，则是浪漫之极。回帖里讲了两件事。一件是他结婚的时候，送给他岳母的礼物是他太太出生那年的一瓶勃艮底酒，是在一家专买纪念酒的网站上买的，很贵。他岳母很感动，因为那瓶红酒让她回忆起很多往事。另外一件是后来他有了一个女儿，他收藏了一箱2000年出品的红酒，他会在她出嫁那天和所有的客人一起喝。

呵，浪漫得让人有种立刻生个女儿的冲动，然后收集一箱，Beaujolais Nouveau虽然好但是无法保存二十来个年头，还是一箱张裕或者长城干红好了，然后等到她出嫁的时候请所有的客人一起喝。', NULL, '2002-11-07 11:15:00', 19, '20021207230247_bbsid_188308_board_13_c3a172d3d3.html', '20021207230247');
